// Generated by OrchestKit Claude Plugin
// Created: 2026-03-03

/**
 * Session Handoff Generator — Writes a structured handoff YAML at session end
 *
 * Location: ~/.claude/analytics/handoffs/{project-hash}/latest.yaml
 * Rotates: keeps last 10 handoffs per project (oldest deleted)
 *
 * Privacy-by-design: project path hashed (SHA256), no raw paths, no prompts.
 * Content stays under 500 tokens to keep injection lean.
 *
 * Hook: SessionEnd
 */

import { existsSync, readFileSync, mkdirSync, readdirSync, unlinkSync } from 'node:fs';
import { join } from 'node:path';
import { execSync } from 'node:child_process';
import type { HookInput, HookResult } from '../types.js';
import { logHook, outputSilentSuccess, getSessionId, getCachedBranch, getProjectDir } from '../lib/common.js';
import { hashProject } from '../lib/analytics.js';
import { getMetricsFile, getHomeDir, joinPath } from '../lib/paths.js';
import { atomicWriteSync } from '../lib/atomic-write.js';

const HOOK_NAME = 'session-handoff-generator';
const MAX_HANDOFFS = 10;

function getHandoffDir(projectHash: string): string {
  return joinPath(getHomeDir(), '.claude', 'analytics', 'handoffs', projectHash);
}

function loadMetrics(): Record<string, unknown> {
  const f = getMetricsFile();
  if (!existsSync(f)) return {};
  try { return JSON.parse(readFileSync(f, 'utf-8')); } catch { return {}; }
}

function countTools(metrics: Record<string, unknown>): number {
  const tools = (metrics.tools as Record<string, number>) || {};
  return Object.values(tools).reduce((s, n) => s + n, 0);
}

function countModifiedFiles(projectDir: string): number {
  try {
    const out = execSync('git status --porcelain 2>/dev/null', {
      cwd: projectDir, encoding: 'utf8', timeout: 3000, stdio: ['pipe', 'pipe', 'pipe'],
    });
    return out.trim().split('\n').filter(Boolean).length;
  } catch { return 0; }
}

function readTaskLog(projectDir: string): { completed: string[]; pending: string[] } {
  const logFile = join(projectDir, '.claude', 'logs', 'task-completions.jsonl');
  if (!existsSync(logFile)) return { completed: [], pending: [] };
  try {
    const lines = readFileSync(logFile, 'utf-8').trim().split('\n').filter(Boolean).slice(-20);
    const completed: string[] = [];
    const pending: string[] = [];
    for (const line of lines) {
      try {
        const e = JSON.parse(line) as { task_subject?: string; task_status?: string };
        if (!e.task_subject?.trim()) continue;
        if (e.task_status === 'completed') completed.push(e.task_subject.trim());
        else if (e.task_status === 'in_progress' || e.task_status === 'pending') pending.push(e.task_subject.trim());
      } catch { /* skip */ }
    }
    return { completed: [...new Set(completed)].slice(-5), pending: [...new Set(pending)].slice(0, 5) };
  } catch { return { completed: [], pending: [] }; }
}

function deriveStatus(totalTools: number, _lastMsg: string | undefined, completed: string[], pending: string[]): string {
  if (totalTools === 0) return 'interrupted';
  if (pending.length > 0) return 'partial';
  if (completed.length > 0) return 'completed';
  return 'partial';
}

function buildSummary(totalTools: number, filesModified: number, completed: string[], branch: string): string {
  if (completed.length > 0) {
    const last = completed[completed.length - 1];
    return last.length > 80 ? `${last.slice(0, 77)}...` : last;
  }
  if (branch && branch !== 'unknown') return `Session on ${branch}: ${totalTools} tool calls, ${filesModified} files modified`;
  return `${totalTools} tool calls, ${filesModified} files modified`;
}

function escapeYamlString(s: string): string {
  return s.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n').replace(/\r/g, '\\r');
}

function toYamlList(items: string[]): string {
  if (items.length === 0) return ' []';
  return `\n${items.map(i => `  - "${escapeYamlString(i)}"`).join('\n')}`;
}

function toYaml(d: {
  session_id: string; project: string; timestamp: string; branch: string;
  status: string; summary: string; files_modified: number; tools_used: number;
  completed: string[]; pending: string[]; next_steps: string[];
}): string {
  return `${[
    `session_id: ${d.session_id}`,
    `project: ${d.project}`,
    `timestamp: ${d.timestamp}`,
    `branch: ${d.branch}`,
    `status: ${d.status}`,
    `summary: "${escapeYamlString(d.summary)}"`,
    `files_modified: ${d.files_modified}`,
    `tools_used: ${d.tools_used}`,
    `completed:${toYamlList(d.completed)}`,
    `pending:${toYamlList(d.pending)}`,
    `next_steps:${toYamlList(d.next_steps)}`,
  ].join('\n')}\n`;
}

function rotateHandoffs(handoffDir: string): void {
  try {
    const files = readdirSync(handoffDir)
      .filter(f => f.startsWith('session-') && f.endsWith('.yaml'))
      .sort(); // ascending: oldest first
    if (files.length < MAX_HANDOFFS) return;
    for (const file of files.slice(0, files.length - MAX_HANDOFFS + 1)) {
      try { unlinkSync(join(handoffDir, file)); } catch { /* ignore */ }
    }
  } catch { /* ignore */ }
}

export function sessionHandoffGenerator(input: HookInput): HookResult {
  try {
    const projectDir = input.project_dir || getProjectDir();
    const projectHash = hashProject(projectDir);
    const handoffDir = getHandoffDir(projectHash);
    const sessionId = input.session_id || getSessionId();
    const branch = getCachedBranch(projectDir);
    const timestamp = new Date().toISOString();

    const metrics = loadMetrics();
    const totalTools = countTools(metrics);
    const filesModified = countModifiedFiles(projectDir);
    const { completed, pending } = readTaskLog(projectDir);

    const status = deriveStatus(totalTools, input.last_assistant_message, completed, pending);
    const summary = buildSummary(totalTools, filesModified, completed, branch);
    const nextSteps = pending.length > 0 ? pending.slice(0, 3)
      : (branch && branch !== 'unknown' && branch !== 'main' && branch !== 'master')
        ? [`Continue work on branch ${branch}`] : [];

    const yaml = toYaml({
      session_id: sessionId, project: projectHash, timestamp, branch, status, summary,
      files_modified: filesModified, tools_used: totalTools, completed, pending, next_steps: nextSteps,
    });

    mkdirSync(handoffDir, { recursive: true });

    // Rotate before writing archive so count is accurate (avoids off-by-one)
    rotateHandoffs(handoffDir);
    const archivePath = join(handoffDir, `session-${timestamp.replace(/[:.]/g, '-')}.yaml`);
    atomicWriteSync(archivePath, yaml);
    atomicWriteSync(join(handoffDir, 'latest.yaml'), yaml);

    logHook(HOOK_NAME, `Handoff written: ${projectHash}/latest.yaml (${totalTools} tools, ${filesModified} files, status=${status})`);
  } catch (err) {
    logHook(HOOK_NAME, `Failed to write handoff: ${err instanceof Error ? err.message : String(err)}`, 'warn');
  }

  return outputSilentSuccess();
}
